- 'Chưa gọi món nào' → {{ $t('customer.orderHistory.emptyTitle') }}
- 'Các món ăn sau khi bạn gửi bếp thành công sẽ xuất hiện ở đây.' → {{ $t('customer.orderHistory.emptyText') }}
- 'Mã Order:' → {{ $t('customer.orderHistory.orderId') }}
- 'Hóa đơn tạm tính tại bàn' → {{ $t('customer.orderHistory.billTitle') }}
- 'Tổng tiền món:' → {{ $t('customer.orderHistory.subtotal') }}
- 'Phí dịch vụ phục vụ (5%):' → {{ $t('customer.orderHistory.serviceCharge') }}
- 'Thuế VAT (8%):' → {{ $t('customer.orderHistory.vat') }}
- 'Chiết khấu/Giảm giá:' → {{ $t('customer.orderHistory.discount') }}
- 'Tổng cộng tạm tính:' → {{ $t('customer.orderHistory.grandTotal') }}
